mapper.sql:
WHERE f.publish_status = 'PUBLISHED'

    AND f.flight_no = #{flightNo}


    AND da.city = #{departureCity}


    AND aa.city = #{arrivalCity}


    AND f.departure_time >= #{departureDate}
    AND f.departure_time < #{departureDate} + INTERVAL 1 DAY

choose.when:
AND EXISTS (SELECT 1 FROM flight_cabin fc
            WHERE fc.flight_id = f.id AND fc.cabin_class = #{cabinClass}
            AND fc.price >= #{minPrice})

AND EXISTS (SELECT 1 FROM flight_cabin fc
            WHERE fc.flight_id = f.id AND fc.cabin_class = #{cabinClass}
            AND fc.price <= #{maxPrice})

AND (
    SELECT COUNT(*) FROM flight_seat fs
    WHERE fs.flight_id = f.id AND fs.cabin_class = #{cabinClass} AND fs.status = 'AVAILABLE'
) >= #{passengerCount}

mapper.select:

WHERE f.publish_status = 'PUBLISHED'
    AND f.departure_time > NOW()
    AND f.status IN ('ON_TIME', 'DELAYED')

    AND da.city = #{departureCity}


    AND aa.city = #{arrivalCity}



        AND f.departure_time >= #{departureDateStart}
        AND f.departure_time < #{departureDateEnd} + INTERVAL 1 DAY


        AND f.departure_time >= #{departureDate}
        AND f.departure_time < #{departureDate} + INTERVAL 1 DAY



    AND f.airline_id = #{airlineId}




            AND EXISTS (SELECT 1 FROM flight_cabin fc
                        WHERE fc.flight_id = f.id AND fc.cabin_class = #{cabinClass}
                        AND fc.price >= #{minPrice})


            AND f.base_price >= #{minPrice}






            AND EXISTS (SELECT 1 FROM flight_cabin fc
                        WHERE fc.flight_id = f.id AND fc.cabin_class = #{cabinClass}
                        AND fc.price <= #{maxPrice})


            AND f.base_price <= #{maxPrice}




    AND TIME(f.departure_time) >= #{departureTimeStart}


    AND TIME(f.departure_time) <= #{departureTimeEnd}


    AND f.duration_minutes <= #{maxDurationMinutes}


    AND f.direct_flag = 1



        AND (
            SELECT COUNT(*) FROM flight_seat fs
            WHERE fs.flight_id = f.id AND fs.cabin_class = #{cabinClass} AND fs.status = 'AVAILABLE'
        ) >= #{passengerCount}


        AND EXISTS (
            SELECT 1 FROM flight_seat fs
            WHERE fs.flight_id = f.id AND fs.cabin_class = #{cabinClass} AND fs.status = 'AVAILABLE'
        )


        AND f.remaining_seats >= #{passengerCount}


ORDER BY ${orderBy}
LIMIT #{limit}

SELECT id, flight_id, seat_no, cabin_class, seat_type, price, status, version,
       locked_by_order_id, lock_expire_time, created_at, updated_at
FROM flight_seat WHERE id = #{id}

