mapper.select:
SELECT id, flight_no, airline_id, departure_airport_id, arrival_airport_id,
       departure_time, arrival_time, duration_minutes, base_price,
       remaining_seats, total_seats, status, publish_status,
       direct_flag, baggage_allowance, punctuality_rate, created_at, updated_at
FROM flight
WHERE departure_airport_id = #{departureAirportId}
  AND arrival_airport_id = #{arrivalAirportId}
  AND id != #{excludeFlightId}
  AND publish_status = 'PUBLISHED'
  AND departure_time > NOW()
  AND status IN ('ON_TIME', 'DELAYED')
  AND remaining_seats >= #{passengerCount}
ORDER BY departure_time
